- **One-to-One Relationship Example**:
  ```typescript
  import { Entity, PrimaryGeneratedColumn, Column, OneToOne, JoinColumn } from 'typeorm';

  @Entity()
  export class User {
    @PrimaryGeneratedColumn()
    id: number;

    @Column()
    name: string;

    @OneToOne(type => Profile)
    @JoinColumn()
    profile: Profile;
  }

  @Entity()
  export class Profile {
    @PrimaryGeneratedColumn()
    id: number;

    @Column()
    bio: string;
  }
  ```

- **Indexes**:
  - Define indexes in your entity decorators to improve query performance.
  ```typescript
  import { Entity, PrimaryGeneratedColumn, Column, Index } from 'typeorm';

  @Entity()
  export class User {
    @PrimaryGeneratedColumn()
    id: number;

    @Column()
    @Index()
    email: string;
  }
  ```

- **Migrations**:
  - Use TypeORM migrations to manage database schema changes.
  ```bash
  npm install --save typeorm-cli
  npx typeorm migration:create -n CreateUsersTable
  npx typeorm migration:run
  ```

